func shortHash(s string) string {
	if len(s) <= 12 {
		return s
	}
	return s[:12]
}

func inputType(q *question) string {
	if q.MaxChoices == 1 {
		return "radio"
	}
	return "checkbox"
}

func questionNoun(n int) string {
	if n == 1 {
		return "question"
	}
	return "questions"
}

func choiceNoun(n int) string {
	if n == 1 {
		return "choice"
	}
	return "choices"
}

